import{l as i,c as a,b as e,ai as t}from"./chunks/framework.DfOqixww.js";const r="/assets/2025-02-09-12-18-17.CrLIa0KL.png",s="/assets/2025-02-09-12-22-47.DSfiELSu.png",o="/assets/2025-02-09-12-34-28.DHQzH1iE.png",n="/assets/2025-02-09-12-37-08.DdrpVXfh.png",c="/assets/2025-02-09-12-39-37.DH-NtOEc.png",h="/assets/2025-02-09-12-43-59.G5_0ALaL.png",p="/assets/2025-02-09-12-49-20.Bf-Afroh.png",k=JSON.parse('{"title":"蔬菜","description":"","frontmatter":{},"headers":[],"relativePath":"favorite/cook/vegetable.md","filePath":"favorite/cook/vegetable.md","lastUpdated":1742622562000}'),d={name:"favorite/cook/vegetable.md"};function u(_,l,m,f,b,g){return e(),a("div",null,l[0]||(l[0]=[t('<h1 id="蔬菜" tabindex="-1">蔬菜 <a class="header-anchor" href="#蔬菜" aria-label="Permalink to &quot;蔬菜&quot;">​</a></h1><h3 id="○-番茄炒蛋" tabindex="-1">○ 番茄炒蛋 <a class="header-anchor" href="#○-番茄炒蛋" aria-label="Permalink to &quot;○ 番茄炒蛋&quot;">​</a></h3><p><img src="'+r+'" alt=""></p><ul><li>番茄，头尾十字花刀，开水烫番茄，去皮</li><li>番茄去芯，横切竖切成块，不要太小</li><li>3 个鸡蛋，加盐、水淀粉，搅匀</li><li>润锅</li><li>3 成油温大火下鸡蛋（比较热，更加蓬松），两面金黄色，捣烂倒出</li><li>炒番茄，炒融，加蒜米、番茄沙司，加鸡蛋</li><li>加少许盐、白糖，加少许水，加葱花，出锅</li></ul><h3 id="○-酸辣土豆丝" tabindex="-1">○ 酸辣土豆丝 <a class="header-anchor" href="#○-酸辣土豆丝" aria-label="Permalink to &quot;○ 酸辣土豆丝&quot;">​</a></h3><p><img src="'+s+'" alt=""></p><ul><li>土豆先宽面切一刀可立稳，切片，扑克牌码开，切丝</li><li>土豆丝清洗</li><li>水开，加盐，焯土豆丝，加白醋更脆，一小会就行不要太软</li><li>润锅</li><li>加干辣椒节、葱段爆香，快速下土豆丝翻炒</li><li>加少许盐、白糖、生抽，锅边加陈醋，加葱花，出锅</li></ul><h3 id="○-清炒丝瓜" tabindex="-1">○ 清炒丝瓜 <a class="header-anchor" href="#○-清炒丝瓜" aria-label="Permalink to &quot;○ 清炒丝瓜&quot;">​</a></h3><p><img src="'+o+'" alt=""></p><ul><li>清水加盐，泡改刀的丝瓜 5-6 分钟，避免发黑</li><li>润锅倒出，热锅凉油</li><li>下切好的姜片、蒜片、葱段、不辣红椒，下丝瓜</li><li>加少许盐、白糖，加蚝油，锅边加一丢丢水，中火 30s</li><li>加少许水淀粉，出锅</li></ul><h3 id="○-青椒炒茄子" tabindex="-1">○ 青椒炒茄子 <a class="header-anchor" href="#○-青椒炒茄子" aria-label="Permalink to &quot;○ 青椒炒茄子&quot;">​</a></h3><p><img src="'+n+'" alt=""></p><ul><li>茄子切片，锅热中火干煸，蔫了倒出</li><li>加菜籽油、猪油，加蒜蓉、几篇姜、青椒丝，加豆豉，加茄子翻炒</li><li>加少许白糖、一点盐、生抽、蚝油，出锅</li></ul><h3 id="○-蒜蓉油麦菜" tabindex="-1">○ 蒜蓉油麦菜 <a class="header-anchor" href="#○-蒜蓉油麦菜" aria-label="Permalink to &quot;○ 蒜蓉油麦菜&quot;">​</a></h3><p><img src="'+c+'" alt=""></p><ul><li>水开，加油，油麦菜段焯水，40s 左右</li><li>润锅倒出，热锅凉油</li><li>加蒜蓉炒香，快速下青菜</li><li>加少许盐、一点白糖、一点生抽，加少许水淀粉，出锅</li></ul><h3 id="○-蚝油菠菜" tabindex="-1">○ 蚝油菠菜 <a class="header-anchor" href="#○-蚝油菠菜" aria-label="Permalink to &quot;○ 蚝油菠菜&quot;">​</a></h3><p><img src="'+h+'" alt=""></p><ul><li>水开，加油盐，下菠菜（先根部再整个），熟了捞出沥干</li><li>润锅倒出，热锅凉油</li><li>加蒜米、干葱末炒香，加两圆勺清水（淋菠菜）</li><li>加少许盐、一点白糖、生抽、一点蚝油，加少许水淀粉（一边倒一边滑匀至微稠），出锅淋菠菜</li></ul><h3 id="○-干锅花菜" tabindex="-1">○ 干锅花菜 <a class="header-anchor" href="#○-干锅花菜" aria-label="Permalink to &quot;○ 干锅花菜&quot;">​</a></h3><p><img src="'+p+'" alt=""></p><ul><li>5 成油温油炸花菜，迅速捞出（熟且有脆度）</li><li>加油、小火煸五花肉，锅边加花雕酒，加拍破的蒜头、小米椒、干辣椒段、干花椒</li><li>加一点老抽、小半勺蚝油，下花菜翻炒，锅边加一点点水，盖上中火一分钟</li><li>加盐、白糖、蒜苗叶，加少许水淀粉，加一点芝麻香油，出锅</li></ul>',22)]))}const P=i(d,[["render",u]]);export{k as __pageData,P as default};
